import pytest
import requests

def test_role_operation_authorisation_matrix(
    joint_account, get_primary_token, get_secondary_token, base_url
):
    account_id = joint_account["id"]
    primary_token = get_primary_token(account_id)
    secondary_token = get_secondary_token(account_id)

    txn_payload = {"type": "debit", "amount": 1.00, "currency": "USD"}
    own_payload = {"operation": "change_ownership", "new_owner_id": "<new_owner_id>"}

    cases = [
        ("primary", primary_token, "POST", txn_payload, (200, 201)),
        ("primary", primary_token, "PATCH", own_payload, (403,)),
        ("secondary", secondary_token, "POST", txn_payload, (200, 201)),
        ("secondary", secondary_token, "PATCH", own_payload, (403,)),
    ]

    url = f"{base_url}/accounts/{account_id}/joint"
    for role, token, method, payload, expected_codes in cases:
        headers = {"Authorization": f"Bearer {token}"}
        resp = requests.request(method, url, json=payload, headers=headers)
        assert resp.status_code in expected_codes, (
            f"role={role} method={method} got {resp.status_code}, expected {expected_codes}"
        )
